INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 2, "2021/10/18 12:00:00", 10077002, 2, 3.099, 1, 53, 190802, 10077, -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 2, "2021/10/18 12:00:00", 10077003, 3, 2.801, 1, 54, 190802, 10077, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 2, "2021/10/18 12:00:00", 10077004, 4, 0.0, 2, 54, 190802, 10077, -416.5, "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 1, "2021/10/18 12:00:00", 10077005, 5, 0.0, 1, 57, 190802, 10077, -416.5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 2, "2021/10/18 12:00:00", 10077006, 1, 5.506, 1, 55, 190802, 10077, -363.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 1, "2021/10/18 12:00:00", 10077007, 2, 1.216, 2, 55, 190802, 10077, -363.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 1, "2021/10/18 12:00:00", 10077008, 3, 1.539, 2, 56, 190802, 10077, -363.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！");
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2021/10/27 14:59:59", 1, "2021/10/18 12:00:00", 10077009, 4, 1.875, 2, 56, 190802, 10077, -363.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！");
