INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, "カリン", "2023/02/27 14:59:59", 1, "2023/02/07 12:00:00", 10111007, 2, 1.216, 2, 55, 190801, 10111, -363.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！");
